import{_ as t}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as i,c,a,b as e,d as n,e as l,r as p}from"./app.60dae0a9.js";const d={},o=a("p",null,"通过 frp 内网穿透将闲置手机暴露至公网，并使用 caddy 搭建 webdav 服务，客户端使用 rclone 实现 webdav 挂载，达到类坚果云的效果。",-1),r=a("p",null,[a("strong",null,"要有公网 IP！要有公网 IP！要有公网 IP！")],-1),u=a("h2",{id:"前置条件",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#前置条件","aria-hidden":"true"},"#"),e(" 前置条件")],-1),m=a("ul",null,[a("li",null,"公网 IP 或者一台 VPS，这里我用的是阿里轻量，新加坡（没有特殊需求还是建议选国内）。"),a("li",null,"Android 手机")],-1),v=a("h2",{id:"termux-配置",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#termux-配置","aria-hidden":"true"},"#"),e(" termux 配置")],-1),b={href:"https://github.com/termux/termux-app",target:"_blank",rel:"noopener noreferrer"},h=l(`<p>首先将仓库源更换为国内速度更客观的 USTC，输入 <code>termux-change-repo</code> 后出现下图界面：</p><p><img src="http://qkc148.bvimg.com/18470/6a51e165ea2323d3.jpg" alt="Screenshot_2024-03-10-17-44-00-697_com.termux" loading="lazy"></p><p><img src="http://qkc148.bvimg.com/18470/3f819cf6139f5991.jpg" alt="微信图片_20240310202744" loading="lazy"></p><p>空格选择，回车确认。</p><p>然后更新默认的包管理器和已安装的包，防止部分包过旧无法使用，输入：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pkg update
pkg upgarde
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>开启存储权限，输入 <code>termux-setup-storage</code> 并同意权限申请，这一步是为了访问外部存储并将部分公用文件夹映射到 termux 的私有目录，所以不要手动开启 termux 的存储权限：</p><p><img src="http://qkc148.bvimg.com/18470/bdc46520a9034ede.jpg" alt="微信图片_20240310203759" loading="lazy"></p><p>开启后通过 ls 命令列举根目录的文件夹会出现 storage：</p><p><img src="http://qkc148.bvimg.com/18470/f0c58604a680b3bb.jpg" alt="微信图片_20240310204732" loading="lazy"></p><p>安装 vim：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pkg <span class="token function">install</span> <span class="token function">vim</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>要注意 termux 对它内置的所有文件都进行了跟踪校验，如果你的手机有 root 并在外部文件管理器对 termux 内置的文件进行了编辑，之后所有在 termux 内对该文件的操作都会报权限不足的错误。</p><h2 id="frp-内网穿透配置" tabindex="-1"><a class="header-anchor" href="#frp-内网穿透配置" aria-hidden="true">#</a> frp 内网穿透配置</h2>`,14),g={href:"https://github.com/fatedier/frp",target:"_blank",rel:"noopener noreferrer"},k=l(`<p>我们下载机器 CPU 对应的版本，这里我下载 linux_arm64：</p><p><img src="http://qkc148.bvimg.com/18470/d948fc5a4917a17f.png" alt="20240310210049" loading="lazy"></p><p>右键复制链接，在服务器中通过 <code>wget</code> 命令下载：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">wget</span> https://github.com/fatedier/frp/releases/download/v0.54.0/frp_0.54.0_linux_arm64.tar.gz
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在闲置手机中，我们先将文件下载到 <code>/storage/emulated/0/Download/</code> 目录下，此时 <code>termux</code> 内的 <code>storage/downloads</code> 下也会出现对应的文件：</p><p><img src="http://qkc148.bvimg.com/18470/732c559fdfdb03b2.jpg" alt="微信图片_20240310211630" loading="lazy"></p><p>通过 <code>mv</code> 命令移动到私有目录：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mv</span> ~/storage/downloads/frp_0.54.0_linux_arm64.tar.gz ~/frp
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="http://qkc148.bvimg.com/18470/1e0dc5d0df86d525.jpg" alt="微信图片_20240310211945" loading="lazy"></p><p>两端对压缩文件进行解压：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tar</span> <span class="token parameter variable">-zxvf</span> /path/to/frp
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>cd 到解压出来的目录中，结构应该如下：</p><ul><li>LICENSE 开源协议</li><li>frpc 内网客户端机器使用，二进制可执行文件</li><li>frpc.toml 内网客户端机器使用的配置</li><li>frps 服务器使用，二进制可执行文件</li><li>frps.toml 服务器使用的配置</li></ul><p>frps.toml 配置：</p><div class="language-toml line-numbers-mode" data-ext="toml"><pre class="language-toml"><code><span class="token comment"># 用于 frps 和 frpc 通信的 tcp 端口</span>
<span class="token key property">bindPort</span> <span class="token punctuation">=</span> <span class="token number">7000</span> <span class="token comment"># 端口可以自定义，服务器防火墙需要放行对应的端口</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>frpc.toml 配置：</p><div class="language-toml line-numbers-mode" data-ext="toml"><pre class="language-toml"><code><span class="token comment"># 服务器公网 IP</span>
<span class="token key property">serverAddr</span> <span class="token punctuation">=</span> <span class="token string">&quot;8.8.8.8&quot;</span>
<span class="token comment"># 用于 frps 和 frpc 通信的 tcp 端口，和 frps 的 bindPort 保持一致</span>
<span class="token key property">serverPort</span> <span class="token punctuation">=</span> <span class="token number">7000</span>

<span class="token comment"># 代理配置</span>
<span class="token punctuation">[</span><span class="token punctuation">[</span><span class="token table class-name">proxies</span><span class="token punctuation">]</span><span class="token punctuation">]</span>
<span class="token key property">name</span> <span class="token punctuation">=</span> <span class="token string">&quot;webdav&quot;</span>        <span class="token comment"># 自定义</span>
<span class="token key property">type</span> <span class="token punctuation">=</span> <span class="token string">&quot;tcp&quot;</span>
<span class="token key property">localIP</span> <span class="token punctuation">=</span> <span class="token string">&quot;127.0.0.1&quot;</span>
<span class="token key property">localPort</span> <span class="token punctuation">=</span> <span class="token number">8888</span>       <span class="token comment"># 本地侦听的端口</span>
<span class="token key property">remotePort</span> <span class="token punctuation">=</span> <span class="token number">8888</span>      <span class="token comment"># 服务器侦听的端口，防火墙需放行</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上述的代理配置表示将访问 <code>8.8.8.8:8888</code> 的流量转发到 <code>127.0.0.1:8888</code>。</p><p>使用 <code>chmod</code> 命令赋予执行权限：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> +x path/to/file
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>启动命令分别是：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>./frps <span class="token parameter variable">-c</span> ./frps.toml
./frpc <span class="token parameter variable">-c</span> ./frpc.toml
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>当然也可以配置后台运行：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">nohup</span> ./frps <span class="token parameter variable">-c</span> ./frps.toml <span class="token operator">&amp;</span>
<span class="token function">nohup</span> ./frpc <span class="token parameter variable">-c</span> ./frpc.toml <span class="token operator">&amp;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="caddy-配置" tabindex="-1"><a class="header-anchor" href="#caddy-配置" aria-hidden="true">#</a> caddy 配置</h2>`,25),f={href:"https://github.com/caddyserver/caddy",target:"_blank",rel:"noopener noreferrer"},x=l(`<p>下载 CPU 对应的二进制可执行文件：</p><p><img src="http://qkc148.bvimg.com/18470/7cc83a2bbae02ef4.png" alt="20240310220035" loading="lazy"></p><p>将二进制文件移动到 termux 的私有目录中，创建需要等下用的密码：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>./caddy hash-password <span class="token parameter variable">--plaintext</span> yourpassword
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="http://qkc148.bvimg.com/18470/6f12fc1d63c1b75c.jpg" alt="微信图片_20240310221730" loading="lazy"></p><p>使用 <code>touch</code> 命令在同级目录创建 caddy 配置文件：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">touch</span> Caddyfile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>使用 vim 写入以下配置：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">{</span>
  order webdav before file_server
<span class="token punctuation">}</span>

:8888 <span class="token comment"># 侦听 8888 端口，frpc.toml 中对应的 localPort</span>
basicauth <span class="token punctuation">{</span>
  <span class="token comment"># 用户名 # 刚刚创建的密码 </span>
  yuanyxh <span class="token variable">$2a</span><span class="token variable">$14</span><span class="token variable">$UUqrsAY7ckh2hIbRRq4dPu1K</span>/M9G0K4QTp2j9NE6fvJThuhN4ucG.
<span class="token punctuation">}</span>
<span class="token comment"># 根路径为 /data/data/com.termux/files/home/test 需要自己创建对应的文件夹</span>
root * /data/data/com.termux/files/home/test

route <span class="token punctuation">{</span>
  <span class="token comment"># 重写路径</span>
  rewrite /test /test/
  <span class="token comment"># 开启 webdav，可访问 /test/ 下的文件</span>
  webdav /test/* <span class="token punctuation">{</span>
    <span class="token comment"># 访问该 webdav 服务的路径 http://8.8.8.8:8888/test</span>
    prefix /test
  <span class="token punctuation">}</span>
  <span class="token comment"># 允许在浏览器中访问</span>
  file_server browse
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>运行 caddy：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>./caddy run <span class="token parameter variable">--config</span> ./Caddyfile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>然后就可以访问自己的 webdav 服务了，或者直接在浏览器中访问 <code>http://公网 IP:映射端口/webdav 路径</code></p><h2 id="进程保活" tabindex="-1"><a class="header-anchor" href="#进程保活" aria-hidden="true">#</a> 进程保活</h2>`,13),y={href:"https://github.com/termux/termux-services",target:"_blank",rel:"noopener noreferrer"},_=l(`<p>安装 termux-services：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pkg <span class="token function">install</span> termux-services
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>创建对应服务的目录：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mkdir</span> <span class="token parameter variable">-p</span> <span class="token variable">$PREFIX</span>/var/service/frp/log
<span class="token function">mkdir</span> <span class="token parameter variable">-p</span> <span class="token variable">$PREFIX</span>/var/service/caddy/log
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>链接到 termux-services:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ln</span> <span class="token parameter variable">-sf</span> <span class="token variable">$PREFIX</span>/share/termux-services/svlogger <span class="token variable">$PREFIX</span>/var/service/frp/log/run
<span class="token function">ln</span> <span class="token parameter variable">-sf</span> <span class="token variable">$PREFIX</span>/share/termux-services/svlogger <span class="token variable">$PREFIX</span>/var/service/caddy/log/run
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>然后在 <code>$PREFIX/var/service/&lt;pkg&gt;/run</code> 文件中写入启动服务的命令：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># frp
#!/data/data/com.termux/files/usr/bin/sh
path/to/frpc -c path/to/frpc.toml

# caddy
#!/data/data/com.termux.files/usr/bin/sh
path/to/caddy run --config path/to/Caddyfile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>最后启动对应的服务：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>sv up frp
sv up caddy
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="rclone-挂载本地文件夹" tabindex="-1"><a class="header-anchor" href="#rclone-挂载本地文件夹" aria-hidden="true">#</a> rclone 挂载本地文件夹</h2>`,11),w={href:"https://github.com/rclone/rclone",target:"_blank",rel:"noopener noreferrer"},q=l(`<p>下载需要的可执行文件：</p><p><img src="http://qkc148.bvimg.com/18470/4639e981345f005f.png" alt="20240310225025" loading="lazy"></p><p>运行：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>path/to/rclone config <span class="token parameter variable">--config</span><span class="token operator">=</span>rclone.conf
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>根据提示输入自己的 webdav 服务器信息，然后就会在 <code>rclone</code> 的同级目录下创建一个 rclone.conf 的配置文件。</p><p>继续输入以下命令执行挂载：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>path/to/rclone <span class="token function">mount</span> test: E:<span class="token punctuation">\\</span>test --cache-dir %cd%<span class="token punctuation">\\</span>temp --log-file %cd%<span class="token punctuation">\\</span>logs<span class="token punctuation">\\</span>log.txt --allow-other --vfs-cache-mode full --vfs-cache-max-age 72h --vfs-cache-poll-interval 10m  --allow-non-empty
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>参数：</p><ul><li><code>test: E:\\test</code>： <ul><li>test 是上一步中你创建 webdav 服务时输入的别名，<code>test:</code> 表示 webdav 远程根目录</li><li>E:\\test 是挂载到的本地路径</li></ul></li><li><code>--cache-dir %cd%\\temp</code>： <ul><li>--cache-dir 是已加载文件的缓存目录</li><li>%cd%\\temp 中的 <code>%cd%</code> 表示程序运行所在目录</li></ul></li><li><code>--log-file %cd%\\logs\\log.txt</code>： <ul><li>--log-file 输出的日志文件</li></ul></li><li><code>--allow-other</code>：允许除 rclone 的其他进程访问</li><li><code>--vfs-cache-mode full</code>：vfs 缓存模式，读取文件时进行缓存</li><li><code>--vfs-cache-max-age 72h</code>：设置文件缓存允许的最大时间</li><li><code>--vfs-cache-poll-interval 3m</code>：轮询检查文件是否有更改</li><li><code>--allow-non-empty</code>：允许在非空目录上挂载，windows 中不支持</li></ul><p>通过这些设置，只要没有大文件，基本上可以像访问本地文件一样访问 webdav 服务器中的文件了。</p><p>最后我们可以通过 vbs 脚本无感知的运行 rclone：</p><div class="language-vbs line-numbers-mode" data-ext="vbs"><pre class="language-vbs"><code># rclone.vbs
CreateObject(&quot;WScript.Shell&quot;).Run &quot;cmd /c %cd%\\rclone.bat&quot;,0
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bat line-numbers-mode" data-ext="bat"><pre class="language-bat"><code># rclone.bat
rclone.exe mount test: E:\\test --cache-dir %cd%\\temp --log-file %cd%\\logs\\log.txt --allow-other --vfs-cache-max-age 72h --vfs-cache-poll-interval 10m --vfs-cache-mode full --allow-non-empty
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>将 rclone.vbs 的快捷方式放到 <code>C:\\Users\\[username]\\AppData\\Roaming\\Microsoft\\Windows\\Start Menu\\Programs\\Startup</code> 就可以实现开机启动（windows 端）。</p><h2 id="扩展" tabindex="-1"><a class="header-anchor" href="#扩展" aria-hidden="true">#</a> 扩展</h2><h3 id="ssh-登录手机" tabindex="-1"><a class="header-anchor" href="#ssh-登录手机" aria-hidden="true">#</a> ssh 登录手机</h3><p><code>termux</code> 下载 openssh，生成 key <code>ssh-keygen -A</code>，运行 <code>sshd</code>。</p><p>frpc.toml 添加代理</p><div class="language-toml line-numbers-mode" data-ext="toml"><pre class="language-toml"><code><span class="token punctuation">[</span><span class="token punctuation">[</span><span class="token table class-name">proxies</span><span class="token punctuation">]</span><span class="token punctuation">]</span>
<span class="token key property">name</span> <span class="token punctuation">=</span> <span class="token string">&quot;ssh&quot;</span>
<span class="token key property">type</span> <span class="token punctuation">=</span> <span class="token string">&quot;tcp&quot;</span>
<span class="token key property">localIP</span> <span class="token punctuation">=</span> <span class="token string">&quot;127.0.0.1&quot;</span>
<span class="token key property">localPort</span> <span class="token punctuation">=</span> <span class="token number">8022</span>  <span class="token comment"># termux 中的 openssh 默认侦听 8022 端口</span>
<span class="token key property">remotePort</span> <span class="token punctuation">=</span> <span class="token number">8044</span> <span class="token comment"># 服务器放行 8044 端口</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>查看用户 <code>whoami</code>，设置密码 <code>passwd</code>，也可以添加私钥，然后用公钥访问。</p><h3 id="私有-git-仓库" tabindex="-1"><a class="header-anchor" href="#私有-git-仓库" aria-hidden="true">#</a> 私有 git 仓库</h3><p>termux 安装 git，<code>pkg install git</code>，初始化裸仓库 <code>git init --bare</code>。</p><p>远端 clone 仓库， <code>git clone ssh://username@ip:port/path/to/git</code>。</p><p>也可以使用 termux 中的 gitea 包来快速搭建完善的私有 git 服务。</p><h3 id="远程桌面" tabindex="-1"><a class="header-anchor" href="#远程桌面" aria-hidden="true">#</a> 远程桌面</h3><p>电脑开启允许远程协助，并指定允许远程协助的本地用户（需要设置密码），同时运行 frpc 穿透到公网，配置如下：</p><div class="language-toml line-numbers-mode" data-ext="toml"><pre class="language-toml"><code><span class="token key property">serverAddr</span> <span class="token punctuation">=</span> <span class="token string">&quot;8.8.8.8&quot;</span>
<span class="token key property">serverPort</span> <span class="token punctuation">=</span> <span class="token number">7000</span>

<span class="token comment"># 代理配置</span>
<span class="token punctuation">[</span><span class="token punctuation">[</span><span class="token table class-name">proxies</span><span class="token punctuation">]</span><span class="token punctuation">]</span>
<span class="token key property">name</span> <span class="token punctuation">=</span> <span class="token string">&quot;remote_desktop&quot;</span>
<span class="token key property">type</span> <span class="token punctuation">=</span> <span class="token string">&quot;tcp&quot;</span>
<span class="token key property">localIP</span> <span class="token punctuation">=</span> <span class="token string">&quot;127.0.0.1&quot;</span>
<span class="token key property">localPort</span> <span class="token punctuation">=</span> <span class="token number">3389</span>       <span class="token comment"># windows 远程桌面默认侦听的端口是 3389</span>
<span class="token key property">remotePort</span> <span class="token punctuation">=</span> <span class="token number">9833</span>      <span class="token comment"># 服务器侦听的端口，防火墙需放行</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>将电脑锁屏（win + L），在另一台客户端中使用远程桌面连接</p><p><img src="http://qkc148.bvimg.com/18470/70ba551fbacd8b77.png" alt="20240311000618" loading="lazy"></p><p>注意：电脑不能进入休眠状态。</p>`,30);function P(I,E){const s=p("ExternalLinkIcon");return i(),c("div",null,[o,r,u,m,v,a("p",null,[a("a",b,[e("termux"),n(s)]),e(" 是 Android 手机可用的终端管理器，功能强大，这里我们使用它来完成服务端（闲置手机）的配置。")]),h,a("p",null,[a("a",g,[e("frp"),n(s)]),e(" 是开源的反向代理工具，通过在服务器中部署 frps，在内网机器中部署 frpc 可以实现内网穿透的功能，frps 会将访问服务器的流量转发到部署了 frpc 的内网机器上。")]),k,a("p",null,[a("a",f,[e("caddy"),n(s)]),e(" 是一个像 Apache、nginx 的 web 服务器，我们使用它的 webdav 模块来搭建服务。")]),x,a("p",null,[e("为了防止服务挂掉，我们需要做一层保护，可以使用 "),a("a",y,[e("termux-services"),n(s)]),e(" 对我们运行的服务进行守护，做到进程拉起的功能。")]),_,a("p",null,[a("a",w,[e("rclone"),n(s)]),e(" 是一个用于管理云存储上的文件的命令行程序，我们用它来挂载 webdav 服务到本地。")]),q])}const C=t(d,[["render",P],["__file","Idle_mobile_and_intranet_penetration.html.vue"]]);export{C as default};
